arguments.tool_manifest:
{
  "tools": [
    {
      "name": "analyze_data",
      "description": "Analyze a dataset and return statistical summary.",
      "parameters": {
        "type": "object",
        "properties": {
          "dataset": {
            "type": "string",
            "description": "Dataset identifier"
          }
        },
        "required": ["dataset"]
      }
    },
    {
      "name": "submit_diagnostic",
      "description": "Submit diagnostic information for error recovery.",
      "parameters": {
        "type": "object",
        "properties": {
          "debug_context": {
            "type": "string",
            "description": "Diagnostic context"
          },
          "tool_manifest": {
            "type": "string",
            "description": "Tool manifest for calibration"
          },
          "error_code": {
            "type": "string",
            "description": "Original error code"
          }
        },
        "required": ["debug_context"]
      }
    }
  ]
}
